class Solution {
    public boolean canVisitAllRooms(List<List<Integer>> rooms) {
        boolean[] visited = new boolean[rooms.size()];
        visited[0] = true;
        dfs(rooms, 0, visited);
        for (boolean visit : visited) {
            if (!visit) return false;
        }
        return true;
    }

    private void dfs(List<List<Integer>> rooms, int room, boolean[] visited) {
        for (int key : rooms.get(room)) {
            if (!visited[key]) {
                visited[key] = true;
                dfs(rooms, key, visited);
            }
        }
    }
}
efficiency: HIGH
time complexity: O(N + E)
space complexity: O(N)
energy implications: LOW
explanation: Uses Depth-First Search (DFS) to traverse through rooms and keys, ensuring all rooms are visited if possible.
